total = sum(counts.values())
assert total > 0

def _to_int(bitstring):
    return int(bitstring, 2) if isinstance(bitstring, str) else int(bitstring)

peak_mass = 0.0
for outcome, c in counts.items():
    x = _to_int(outcome)
    if x in expected_peaks:
        peak_mass += c

